//
//  CMSTrainerModels.swift
//  FitToday
//
//  DTOs for CMS Trainer & Program API integration.
//  Supports: /api/trainers, /api/trainers/[id], /api/trainers/[id]/reviews,
//            /api/trainers/count, /api/programs, /api/programs/[id]
//

import Foundation

// MARK: - Trainer List Response

struct CMSTrainerListResponse: Codable, Sendable {
    let trainers: [CMSTrainer]
    let total: Int?
    let hasMore: Bool?
}

// MARK: - Trainer Count Response

struct CMSTrainerCountResponse: Codable, Sendable {
    let count: Int
}

// MARK: - CMS Trainer Profile Location

struct CMSTrainerLocation: Codable, Sendable {
    let city: String?
    let state: String?
}

// MARK: - CMS Trainer Profile (nested object in API response)

struct CMSTrainerProfile: Codable, Sendable {
    let bio: String?
    let specialties: [String]?
    let certifications: [String]?
    let experience: Int?
    let location: CMSTrainerLocation?
}

// MARK: - CMS Trainer Stats

struct CMSTrainerStats: Codable, Sendable {
    let rating: Double?
    let totalReviews: Int?
    let totalStudents: Int?
}

// MARK: - CMS Trainer DTO

struct CMSTrainer: Codable, Sendable, Identifiable {
    let id: String
    let displayName: String
    let email: String?
    let photoURL: String?
    let profile: CMSTrainerProfile?
    let stats: CMSTrainerStats?
    let isActive: Bool?
    let inviteCode: String?
    let createdAt: Date?

    // Convenience accessors for nested fields
    var bio: String? { profile?.bio }
    var specializations: [String] { profile?.specialties ?? [] }
    var city: String? { profile?.location?.city }
    var rating: Double? { stats?.rating }
    var reviewCount: Int? { stats?.totalReviews }
    var currentStudentCount: Int? { stats?.totalStudents }
    var maxStudents: Int? { nil }
}

// MARK: - Trainer Review List Response

struct CMSTrainerReviewListResponse: Codable, Sendable {
    let reviews: [CMSTrainerReview]
    let total: Int?
    let limit: Int?
    let offset: Int?
}

// MARK: - CMS Trainer Review DTO

struct CMSTrainerReview: Codable, Sendable, Identifiable {
    let id: String
    let trainerId: String
    let studentId: String
    let studentName: String?
    let rating: Int
    let comment: String?
    let createdAt: Date?
}

// MARK: - Connection Request

struct CMSConnectionRequest: Codable, Sendable {
    let studentId: String
    let studentName: String
}

// MARK: - Connection Response

struct CMSConnectionResponse: Codable, Sendable {
    let id: String
    let trainerId: String
    let studentId: String
    let status: String
    let createdAt: Date?
}

// MARK: - Connection Status Response

struct CMSConnectionStatusResponse: Codable, Sendable {
    let connected: Bool
    let status: String?
    let relationshipId: String?
    let connectedAt: Date?
}

// MARK: - Create Review Request

struct CMSCreateReviewRequest: Codable, Sendable {
    let studentId: String
    let studentName: String
    let rating: Int
    let comment: String?
}

// MARK: - Program List Response

struct CMSProgramListResponse: Codable, Sendable {
    let programs: [CMSProgram]
    let total: Int?
    let limit: Int?
}

// MARK: - CMS Program DTO

struct CMSProgram: Codable, Sendable, Identifiable {
    let id: String
    let trainerId: String
    let title: String
    let description: String?
    let category: String?
    let durationWeeks: Int?
    let difficulty: String?
    let imageUrl: String?
    let isPublished: Bool?
    let workoutCount: Int?
    let createdAt: Date?
    let updatedAt: Date?
}

// MARK: - User Profile Response

struct CMSUserProfileResponse: Codable, Sendable {
    let uid: String
    let role: String?
    let displayName: String?
}

//
//  CMSWorkoutModels.swift
//  FitToday
//
//  DTOs for CMS Personal Trainer API integration.
//  Supports endpoints: /api/workouts, /api/workouts/[id], progress, feedback
//

import Foundation

// MARK: - CMS Workout Response

/// Response wrapper for paginated workout lists from CMS API.
struct CMSWorkoutListResponse: Codable, Sendable {
    let workouts: [CMSWorkout]
    let total: Int
    let page: Int
    let limit: Int
    let hasMore: Bool
}

// MARK: - CMS Workout DTO

/// DTO for workout data from CMS API.
/// Matches: GET /api/workouts and GET /api/workouts/[id]
struct CMSWorkout: Codable, Sendable, Identifiable {
    let id: String
    let trainerId: String
    let studentId: String
    let title: String
    let description: String?
    let focus: String
    let estimatedDurationMinutes: Int
    let intensity: String
    let phases: [CMSWorkoutPhase]
    let schedule: CMSWorkoutSchedule?
    let status: CMSWorkoutStatus
    let pdfUrl: String?
    let version: Int
    let createdAt: Date
    let updatedAt: Date
}

// MARK: - CMS Workout Phase

/// Phase/section within a CMS workout.
struct CMSWorkoutPhase: Codable, Sendable {
    let name: String
    let order: Int
    let items: [CMSWorkoutItem]
}

// MARK: - CMS Workout Item

/// Individual exercise within a workout phase.
struct CMSWorkoutItem: Codable, Sendable {
    let id: String
    let exerciseId: Int?
    let exerciseName: String
    let sets: Int
    let reps: String
    let weight: String?
    let restSeconds: Int
    let notes: String?
    let order: Int
    let mediaUrl: String?
}

// MARK: - CMS Workout Schedule

/// Schedule configuration for CMS workouts.
struct CMSWorkoutSchedule: Codable, Sendable {
    let type: String
    let scheduledDate: Date?
    let dayOfWeek: Int?
    let recurrence: String?
}

// MARK: - CMS Workout Status

/// Status of a workout in the CMS system.
enum CMSWorkoutStatus: String, Codable, Sendable {
    case draft
    case active
    case completed
    case archived
    case deleted
}

// MARK: - CMS Workout Progress

/// Progress data for a workout.
/// Matches: GET /api/workouts/[id]/progress
struct CMSWorkoutProgress: Codable, Sendable {
    let workoutId: String
    let studentId: String
    let completedSessions: Int
    let totalSessions: Int
    let lastSessionDate: Date?
    let exerciseProgress: [CMSExerciseProgress]
    let overallProgress: Double
}

// MARK: - CMS Exercise Progress

/// Progress for an individual exercise.
struct CMSExerciseProgress: Codable, Sendable {
    let exerciseId: String
    let exerciseName: String
    let completedSets: Int
    let targetSets: Int
    let maxWeight: Double?
    let notes: String?
}

// MARK: - CMS Feedback

/// Feedback data for a workout.
/// Matches: GET/POST /api/workouts/[id]/feedback
struct CMSWorkoutFeedback: Codable, Sendable, Identifiable {
    let id: String
    let workoutId: String
    let studentId: String
    let trainerId: String?
    let type: CMSFeedbackType
    let message: String
    let rating: Int?
    let createdAt: Date
    let repliedAt: Date?
    let replyMessage: String?
}

// MARK: - CMS Feedback Type

/// Type of feedback in the CMS system.
enum CMSFeedbackType: String, Codable, Sendable {
    case general
    case difficulty
    case exercise
    case completion
    case question
}

// MARK: - CMS Feedback Request

/// Request body for posting feedback.
/// Matches: POST /api/workouts/[id]/feedback
struct CMSFeedbackRequest: Codable, Sendable {
    let type: CMSFeedbackType
    let message: String
    let rating: Int?

    init(type: CMSFeedbackType, message: String, rating: Int? = nil) {
        self.type = type
        self.message = message
        self.rating = rating
    }
}

// MARK: - CMS Workout Update Request

/// Request body for updating a workout.
/// Matches: PATCH /api/workouts/[id]
struct CMSWorkoutUpdateRequest: Codable, Sendable {
    let status: CMSWorkoutStatus?
    let title: String?
    let description: String?

    init(status: CMSWorkoutStatus? = nil, title: String? = nil, description: String? = nil) {
        self.status = status
        self.title = title
        self.description = description
    }
}

// MARK: - CMS Student Registration

/// Request body for registering a student in the CMS.
/// Matches: POST /api/students
struct CMSStudentRegistrationRequest: Codable, Sendable {
    let firebaseUid: String
    let trainerId: String
    let displayName: String
    let email: String?
}

/// Response from student registration.
/// The API returns the raw Firestore document — only `id` is guaranteed.
struct CMSStudentRegistrationResponse: Codable, Sendable {
    let id: String
}

// MARK: - CMS API Error Response

/// Error response from CMS API.
struct CMSAPIError: Codable, Sendable, LocalizedError {
    let code: String
    let message: String
    let details: String?

    var errorDescription: String? { message }
}

//
//  CMSTrainerService.swift
//  FitToday
//
//  Actor-based service for CMS Trainer & Program API endpoints.
//

import Foundation

actor CMSTrainerService {

    // MARK: - Properties

    private let session: URLSession
    private let configuration: CMSConfiguration
    private let tokenProvider: CMSTokenProvider?
    private let decoder: JSONDecoder
    private let encoder: JSONEncoder

    // MARK: - Initialization

    init(configuration: CMSConfiguration = .default, tokenProvider: CMSTokenProvider? = nil) {
        self.configuration = configuration
        self.tokenProvider = tokenProvider

        let sessionConfig = URLSessionConfiguration.default
        sessionConfig.timeoutIntervalForRequest = configuration.timeout
        sessionConfig.timeoutIntervalForResource = configuration.timeout * 2
        self.session = URLSession(configuration: sessionConfig)

        self.decoder = JSONDecoder()
        self.decoder.dateDecodingStrategy = .iso8601

        self.encoder = JSONEncoder()
        self.encoder.dateEncodingStrategy = .iso8601
    }

    // MARK: - Trainers API

    /// GET /api/trainers — List active trainers (marketplace).
    func fetchTrainers(
        limit: Int = 20,
        offset: Int = 0,
        specialty: String? = nil,
        city: String? = nil
    ) async throws -> CMSTrainerListResponse {
        var components = URLComponents(url: configuration.baseURL.appendingPathComponent("/api/trainers"), resolvingAgainstBaseURL: true)!
        components.queryItems = [
            URLQueryItem(name: "limit", value: String(limit)),
            URLQueryItem(name: "offset", value: String(offset))
        ]
        if let specialty, !specialty.isEmpty {
            components.queryItems?.append(URLQueryItem(name: "specialty", value: specialty))
        }
        if let city, !city.isEmpty {
            components.queryItems?.append(URLQueryItem(name: "city", value: city))
        }
        guard let url = components.url else { throw CMSServiceError.invalidURL }
        let request = try await buildRequest(url: url, method: "GET")
        return try await execute(request: request)
    }

    /// GET /api/trainers/count — Total active trainers.
    func fetchTrainerCount() async throws -> CMSTrainerCountResponse {
        let url = configuration.baseURL.appendingPathComponent("/api/trainers/count")
        let request = try await buildRequest(url: url, method: "GET")
        return try await execute(request: request)
    }

    /// GET /api/trainers/[id] — Public trainer profile.
    func fetchTrainer(id: String) async throws -> CMSTrainer {
        let url = configuration.baseURL.appendingPathComponent("/api/trainers/\(id)")
        let request = try await buildRequest(url: url, method: "GET")
        return try await execute(request: request)
    }

    /// GET /api/trainers/[id]/reviews — Trainer reviews.
    func fetchTrainerReviews(
        trainerId: String,
        limit: Int = 20,
        offset: Int = 0
    ) async throws -> CMSTrainerReviewListResponse {
        var components = URLComponents(url: configuration.baseURL.appendingPathComponent("/api/trainers/\(trainerId)/reviews"), resolvingAgainstBaseURL: true)!
        components.queryItems = [
            URLQueryItem(name: "limit", value: String(limit)),
            URLQueryItem(name: "offset", value: String(offset))
        ]
        guard let url = components.url else { throw CMSServiceError.invalidURL }
        let request = try await buildRequest(url: url, method: "GET")
        return try await execute(request: request)
    }

    // MARK: - Connection API

    /// POST /api/trainers/[id]/connect — Request connection with a trainer.
    func requestConnection(
        trainerId: String,
        connection: CMSConnectionRequest
    ) async throws -> CMSConnectionResponse {
        let url = configuration.baseURL.appendingPathComponent("/api/trainers/\(trainerId)/connect")
        var request = try await buildRequest(url: url, method: "POST", requiresAuth: true)
        request.httpBody = try encoder.encode(connection)
        return try await execute(request: request)
    }

    /// GET /api/trainers/[id]/connect — Check connection status with a trainer.
    func checkConnectionStatus(
        trainerId: String,
        studentId: String
    ) async throws -> CMSConnectionStatusResponse {
        var components = URLComponents(url: configuration.baseURL.appendingPathComponent("/api/trainers/\(trainerId)/connect"), resolvingAgainstBaseURL: true)!
        components.queryItems = [
            URLQueryItem(name: "studentId", value: studentId)
        ]
        guard let url = components.url else { throw CMSServiceError.invalidURL }
        let request = try await buildRequest(url: url, method: "GET", requiresAuth: true)
        return try await execute(request: request)
    }

    // MARK: - Reviews API

    /// POST /api/trainers/[id]/reviews — Submit a review for a trainer.
    func submitReview(
        trainerId: String,
        review: CMSCreateReviewRequest
    ) async throws -> CMSTrainerReview {
        let url = configuration.baseURL.appendingPathComponent("/api/trainers/\(trainerId)/reviews")
        var request = try await buildRequest(url: url, method: "POST", requiresAuth: true)
        request.httpBody = try encoder.encode(review)
        return try await execute(request: request)
    }

    // MARK: - Programs API

    /// GET /api/programs — List published programs.
    func fetchPrograms(
        trainerId: String? = nil,
        category: String? = nil,
        limit: Int = 50
    ) async throws -> CMSProgramListResponse {
        var components = URLComponents(url: configuration.baseURL.appendingPathComponent("/api/programs"), resolvingAgainstBaseURL: true)!
        components.queryItems = [
            URLQueryItem(name: "limit", value: String(limit))
        ]
        if let trainerId, !trainerId.isEmpty {
            components.queryItems?.append(URLQueryItem(name: "trainerId", value: trainerId))
        }
        if let category, !category.isEmpty {
            components.queryItems?.append(URLQueryItem(name: "category", value: category))
        }
        guard let url = components.url else { throw CMSServiceError.invalidURL }
        let request = try await buildRequest(url: url, method: "GET")
        return try await execute(request: request)
    }

    /// GET /api/programs/[id] — Program details.
    func fetchProgram(id: String) async throws -> CMSProgram {
        let url = configuration.baseURL.appendingPathComponent("/api/programs/\(id)")
        let request = try await buildRequest(url: url, method: "GET")
        return try await execute(request: request)
    }

    // MARK: - User Role API

    /// POST /api/users/me — Ensure the current user has role "student" in the CMS.
    /// This must be called before attempting to connect with a trainer.
    func ensureStudentRole(displayName: String) async throws {
        let url = configuration.baseURL.appendingPathComponent("/api/users/me")
        var request = try await buildRequest(url: url, method: "POST", requiresAuth: true)
        let body: [String: String] = ["role": "student", "displayName": displayName]
        request.httpBody = try encoder.encode(body)
        let response: CMSUserProfileResponse = try await execute(request: request)
        #if DEBUG
        print("[CMSTrainerService] ensureStudentRole succeeded — uid: \(response.uid), role: \(response.role ?? "nil")")
        #endif
    }

    // MARK: - Private Helpers

    private func buildRequest(url: URL, method: String, requiresAuth: Bool = false) async throws -> URLRequest {
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("application/json", forHTTPHeaderField: "Accept")

        if requiresAuth {
            if let tokenProvider {
                let token = try await tokenProvider()
                request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
            } else if let apiKey = configuration.apiKey {
                request.setValue("Bearer \(apiKey)", forHTTPHeaderField: "Authorization")
            }
        }

        return request
    }

    private func execute<T: Decodable>(request: URLRequest) async throws -> T {
        #if DEBUG
        print("[CMSTrainerService] \(request.httpMethod ?? "GET") \(request.url?.absoluteString ?? "")")
        #endif

        let (data, response) = try await session.data(for: request)

        guard let httpResponse = response as? HTTPURLResponse else {
            throw CMSServiceError.invalidResponse
        }

        #if DEBUG
        print("[CMSTrainerService] Status: \(httpResponse.statusCode)")
        #endif

        switch httpResponse.statusCode {
        case 200...299:
            do {
                return try decoder.decode(T.self, from: data)
            } catch {
                #if DEBUG
                print("[CMSTrainerService] Decode error: \(error)")
                if let json = String(data: data, encoding: .utf8) {
                    print("[CMSTrainerService] Response: \(json.prefix(500))")
                }
                #endif
                throw CMSServiceError.decodingFailed(error)
            }
        case 401:
            #if DEBUG
            if let body = String(data: data, encoding: .utf8) {
                print("[CMSTrainerService] 401 body: \(body.prefix(500))")
            }
            #endif
            throw CMSServiceError.unauthorized
        case 403:
            #if DEBUG
            if let body = String(data: data, encoding: .utf8) {
                print("[CMSTrainerService] 403 body: \(body.prefix(500))")
            }
            #endif
            throw CMSServiceError.forbidden
        case 404: throw CMSServiceError.notFound
        case 429: throw CMSServiceError.rateLimited
        case 500...599: throw CMSServiceError.serverError(httpResponse.statusCode)
        default:
            if let apiError = try? decoder.decode(CMSAPIError.self, from: data) {
                throw CMSServiceError.apiError(apiError)
            }
            throw CMSServiceError.unexpectedStatus(httpResponse.statusCode)
        }
    }
}

//
//  CMSWorkoutService.swift
//  FitToday
//
//  Actor-based service for CMS Personal Trainer API integration.
//  Handles all REST API interactions for trainer workouts.
//

import Foundation

// MARK: - CMS Configuration

/// Configuration for CMS API connection.
struct CMSConfiguration: Sendable {
    let baseURL: URL
    let apiKey: String?
    let timeout: TimeInterval

    static let `default` = CMSConfiguration(
        baseURL: URL(string: "https://web-cms-pink.vercel.app")!,
        apiKey: nil,
        timeout: 30
    )

    init(baseURL: URL, apiKey: String? = nil, timeout: TimeInterval = 30) {
        self.baseURL = baseURL
        self.apiKey = apiKey
        self.timeout = timeout
    }
}

// MARK: - CMS Workout Service

/// Provides a Firebase Auth ID token for CMS API requests.
typealias CMSTokenProvider = @Sendable () async throws -> String

/// Actor-based service for CMS workout API operations.
///
/// Provides type-safe access to all CMS workout endpoints:
/// - GET/POST /api/workouts
/// - GET/PATCH/DELETE /api/workouts/[id]
/// - GET /api/workouts/[id]/progress
/// - GET/POST /api/workouts/[id]/feedback
actor CMSWorkoutService {

    // MARK: - Properties

    private let session: URLSession
    private let configuration: CMSConfiguration
    private let tokenProvider: CMSTokenProvider?
    private let decoder: JSONDecoder
    private let encoder: JSONEncoder

    // MARK: - Initialization

    init(configuration: CMSConfiguration = .default, tokenProvider: CMSTokenProvider? = nil) {
        self.configuration = configuration
        self.tokenProvider = tokenProvider

        let sessionConfig = URLSessionConfiguration.default
        sessionConfig.timeoutIntervalForRequest = configuration.timeout
        sessionConfig.timeoutIntervalForResource = configuration.timeout * 2
        self.session = URLSession(configuration: sessionConfig)

        self.decoder = JSONDecoder()
        self.decoder.dateDecodingStrategy = .iso8601

        self.encoder = JSONEncoder()
        self.encoder.dateEncodingStrategy = .iso8601
    }

    // MARK: - Workouts API

    /// Fetches workouts for a student from the CMS.
    ///
    /// - Parameters:
    ///   - studentId: The student's user ID.
    ///   - trainerId: Optional trainer ID to filter by.
    ///   - page: Page number for pagination (default: 1).
    ///   - limit: Number of items per page (default: 20).
    /// - Returns: A paginated list of workouts.
    /// - Throws: CMSServiceError if the request fails.
    func fetchWorkouts(
        studentId: String,
        trainerId: String? = nil,
        page: Int = 1,
        limit: Int = 20
    ) async throws -> CMSWorkoutListResponse {
        var components = URLComponents(url: configuration.baseURL.appendingPathComponent("/api/workouts"), resolvingAgainstBaseURL: true)!
        components.queryItems = [
            URLQueryItem(name: "studentId", value: studentId),
            URLQueryItem(name: "page", value: String(page)),
            URLQueryItem(name: "limit", value: String(limit))
        ]

        if let trainerId {
            components.queryItems?.append(URLQueryItem(name: "trainerId", value: trainerId))
        }

        guard let url = components.url else {
            throw CMSServiceError.invalidURL
        }

        let request = try await buildRequest(url: url, method: "GET")
        return try await execute(request: request)
    }

    /// Fetches a single workout by ID.
    ///
    /// - Parameter id: The workout ID.
    /// - Returns: The workout details.
    /// - Throws: CMSServiceError if the request fails.
    func fetchWorkout(id: String) async throws -> CMSWorkout {
        let url = configuration.baseURL.appendingPathComponent("/api/workouts/\(id)")
        let request = try await buildRequest(url: url, method: "GET")
        return try await execute(request: request)
    }

    /// Updates a workout's status or metadata.
    ///
    /// - Parameters:
    ///   - id: The workout ID.
    ///   - update: The update request body.
    /// - Returns: The updated workout.
    /// - Throws: CMSServiceError if the request fails.
    func updateWorkout(id: String, update: CMSWorkoutUpdateRequest) async throws -> CMSWorkout {
        let url = configuration.baseURL.appendingPathComponent("/api/workouts/\(id)")
        var request = try await buildRequest(url: url, method: "PATCH")
        request.httpBody = try encoder.encode(update)
        return try await execute(request: request)
    }

    /// Marks a workout as deleted (soft delete).
    ///
    /// - Parameter id: The workout ID.
    /// - Throws: CMSServiceError if the request fails.
    func deleteWorkout(id: String) async throws {
        let url = configuration.baseURL.appendingPathComponent("/api/workouts/\(id)")
        let request = try await buildRequest(url: url, method: "DELETE")
        let _: EmptyResponse = try await execute(request: request)
    }

    // MARK: - Progress API

    /// Fetches the student's progress for a workout.
    ///
    /// - Parameter workoutId: The workout ID.
    /// - Returns: The progress data.
    /// - Throws: CMSServiceError if the request fails.
    func fetchProgress(workoutId: String) async throws -> CMSWorkoutProgress {
        let url = configuration.baseURL.appendingPathComponent("/api/workouts/\(workoutId)/progress")
        let request = try await buildRequest(url: url, method: "GET")
        return try await execute(request: request)
    }

    // MARK: - Feedback API

    /// Fetches all feedback for a workout.
    ///
    /// - Parameter workoutId: The workout ID.
    /// - Returns: An array of feedback items.
    /// - Throws: CMSServiceError if the request fails.
    func fetchFeedback(workoutId: String) async throws -> [CMSWorkoutFeedback] {
        let url = configuration.baseURL.appendingPathComponent("/api/workouts/\(workoutId)/feedback")
        let request = try await buildRequest(url: url, method: "GET")
        return try await execute(request: request)
    }

    /// Posts new feedback for a workout.
    ///
    /// - Parameters:
    ///   - workoutId: The workout ID.
    ///   - feedback: The feedback request body.
    /// - Returns: The created feedback.
    /// - Throws: CMSServiceError if the request fails.
    func postFeedback(workoutId: String, feedback: CMSFeedbackRequest) async throws -> CMSWorkoutFeedback {
        let url = configuration.baseURL.appendingPathComponent("/api/workouts/\(workoutId)/feedback")
        var request = try await buildRequest(url: url, method: "POST")
        request.httpBody = try encoder.encode(feedback)
        return try await execute(request: request)
    }

    // MARK: - Student Registration API

    /// Registers a student in the CMS so the trainer can assign workouts.
    ///
    /// - Parameters:
    ///   - firebaseUid: The student's Firebase UID.
    ///   - trainerId: The trainer's ID.
    ///   - displayName: The student's display name.
    ///   - email: The student's email (optional).
    /// - Returns: The registration response.
    /// - Throws: CMSServiceError if the request fails.
    func registerStudent(
        firebaseUid: String,
        trainerId: String,
        displayName: String,
        email: String?
    ) async throws -> CMSStudentRegistrationResponse {
        let url = configuration.baseURL.appendingPathComponent("/api/students")
        var request = try await buildRequest(url: url, method: "POST")
        let body = CMSStudentRegistrationRequest(
            firebaseUid: firebaseUid,
            trainerId: trainerId,
            displayName: displayName,
            email: email
        )
        request.httpBody = try encoder.encode(body)
        return try await execute(request: request)
    }

    // MARK: - Private Helpers

    private func buildRequest(url: URL, method: String) async throws -> URLRequest {
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("application/json", forHTTPHeaderField: "Accept")

        // Prefer dynamic token from Firebase Auth; fall back to static apiKey
        if let tokenProvider {
            let token = try await tokenProvider()
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        } else if let apiKey = configuration.apiKey {
            request.setValue("Bearer \(apiKey)", forHTTPHeaderField: "Authorization")
        }

        return request
    }

    private func execute<T: Decodable>(request: URLRequest) async throws -> T {
        #if DEBUG
        print("[CMSWorkoutService] \(request.httpMethod ?? "GET") \(request.url?.absoluteString ?? "")")
        #endif

        let (data, response) = try await session.data(for: request)

        guard let httpResponse = response as? HTTPURLResponse else {
            throw CMSServiceError.invalidResponse
        }

        #if DEBUG
        print("[CMSWorkoutService] Status: \(httpResponse.statusCode)")
        #endif

        switch httpResponse.statusCode {
        case 200...299:
            do {
                return try decoder.decode(T.self, from: data)
            } catch {
                #if DEBUG
                print("[CMSWorkoutService] Decode error: \(error)")
                if let json = String(data: data, encoding: .utf8) {
                    print("[CMSWorkoutService] Response: \(json.prefix(500))")
                }
                #endif
                throw CMSServiceError.decodingFailed(error)
            }

        case 401:
            throw CMSServiceError.unauthorized

        case 403:
            throw CMSServiceError.forbidden

        case 404:
            throw CMSServiceError.notFound

        case 429:
            throw CMSServiceError.rateLimited

        case 500...599:
            throw CMSServiceError.serverError(httpResponse.statusCode)

        default:
            if let apiError = try? decoder.decode(CMSAPIError.self, from: data) {
                throw CMSServiceError.apiError(apiError)
            }
            throw CMSServiceError.unexpectedStatus(httpResponse.statusCode)
        }
    }
}

// MARK: - Empty Response

/// Used for endpoints that return no body on success.
private struct EmptyResponse: Decodable {}

// MARK: - CMS Service Error

/// Errors that can occur during CMS API operations.
enum CMSServiceError: LocalizedError, Sendable {
    case invalidURL
    case invalidResponse
    case unauthorized
    case forbidden
    case notFound
    case rateLimited
    case serverError(Int)
    case unexpectedStatus(Int)
    case decodingFailed(Error)
    case apiError(CMSAPIError)
    case networkError(Error)

    var errorDescription: String? {
        switch self {
        case .invalidURL:
            return NSLocalizedString("cms_service.error.invalid_url", comment: "")
        case .invalidResponse:
            return NSLocalizedString("cms_service.error.invalid_response", comment: "")
        case .unauthorized:
            return NSLocalizedString("cms_service.error.unauthorized", comment: "")
        case .forbidden:
            return NSLocalizedString("cms_service.error.forbidden", comment: "")
        case .notFound:
            return NSLocalizedString("cms_service.error.not_found", comment: "")
        case .rateLimited:
            return NSLocalizedString("cms_service.error.rate_limited", comment: "")
        case .serverError(let code):
            return String(format: NSLocalizedString("cms_service.error.server_error", comment: ""), code)
        case .unexpectedStatus(let code):
            return String(format: NSLocalizedString("cms_service.error.unexpected", comment: ""), code)
        case .decodingFailed:
            return NSLocalizedString("cms_service.error.decoding", comment: "")
        case .apiError(let error):
            return error.message
        case .networkError:
            return NSLocalizedString("cms_service.error.network", comment: "")
        }
    }
}

